import{_ as r,o as s,c as e,ag as i}from"./chunks/framework.ETe_P6d1.js";const o="/kaiping-reports/assets/1.CWkondTI.jpg",_="/kaiping-reports/assets/2.D152Ibz_.jpg",n="/kaiping-reports/assets/3.D3_S_xlZ.jpg",l="/kaiping-reports/assets/4.NmVhRIsI.jpg",c="/kaiping-reports/assets/5.BXzgquo9.jpg",t="/kaiping-reports/assets/6.1jTNzaK5.jpg",p="/kaiping-reports/assets/7.DMH4oukT.jpg",h="/kaiping-reports/assets/8.DNSZFjkc.jpg",d="/kaiping-reports/assets/9.BqtOLe3P.jpg",m="/kaiping-reports/assets/10.-dSLpqtd.jpg",g="/kaiping-reports/assets/11.CTnr-uwB.jpg",u="/kaiping-reports/assets/12.Cco0ixL9.jpg",S=JSON.parse('{"title":"关于濂川司徒公祠的空间秩序与场所精神的调研报告","description":"","frontmatter":{},"headers":[],"relativePath":"reports/张紫凝/关于濂川司徒公祠的空间秩序与场所精神的调研报告.md","filePath":"reports/张紫凝/关于濂川司徒公祠的空间秩序与场所精神的调研报告.md"}'),k={name:"reports/张紫凝/关于濂川司徒公祠的空间秩序与场所精神的调研报告.md"};function q(b,a,f,x,P,j){return s(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="关于濂川司徒公祠的空间秩序与场所精神的调研报告" tabindex="-1">关于濂川司徒公祠的空间秩序与场所精神的调研报告 <a class="header-anchor" href="#关于濂川司徒公祠的空间秩序与场所精神的调研报告" aria-label="Permalink to &quot;关于濂川司徒公祠的空间秩序与场所精神的调研报告&quot;">​</a></h1><p>**作者：张紫凝</p><h2 id="一、引言-宗族祠堂之于广东民系文化的特殊意义" tabindex="-1">一、引言：宗族祠堂之于广东民系文化的特殊意义 <a class="header-anchor" href="#一、引言-宗族祠堂之于广东民系文化的特殊意义" aria-label="Permalink to &quot;一、引言：宗族祠堂之于广东民系文化的特殊意义&quot;">​</a></h2><p>明清以后在华南地区发展起来的所谓“宗族”并不是中国历史上从来就有的制度，也不是所有中国人的社会共有的制度。修谱、建祠、祭祖原本只是皇族与门阀特权，而自宋明理学的推广，诞生的宗族——宗族祠堂，它的空间秩序与场所精神，承载着身份认同、宗法伦理、社会科技发展水平以体现及岭南特色气候影响营造等重要意义。</p><p>在五邑地区，既有南北合流、庄重古朴的传统建筑风格的祠堂，也有中西合璧、风貌优雅的骑楼式建筑风格的祠堂，难以数计。然而，由于历史原因，以及随着新的社会管理体系的出现，祠堂原有的功能日益消退，大多被挪用，也有许多在城市现代化的进程中被拆除。濂川司徒公祠保留传统三进院落格局，而塘口墟仓东村侯成谢公祠、坚翁祠堂等，则呈现出侨乡建筑特征，与传统宗祠形成鲜明对比。近年来，随着赤坎古镇文旅开发与的介入，传统礼制空间的场所氛围受到一定影响，这引发了笔者关于传统宗祠空间秩序特色、场所精神传承的思考。</p><p>基于此，本文以濂川司徒公祠的空间秩序与场所精神为核心研究主题，以出现中西合璧特征的塘口墟仓东村侯成谢公祠和赤坎古镇坚翁祠堂为对比参照，探讨当下传统文化认同与宗族祠堂的活性转化方向。</p><h2 id="二、空间秩序-礼制内核的空间投射" tabindex="-1">二、空间秩序：礼制内核的空间投射 <a class="header-anchor" href="#二、空间秩序-礼制内核的空间投射" aria-label="Permalink to &quot;二、空间秩序：礼制内核的空间投射&quot;">​</a></h2><p>空间秩序是礼制伦理和文化功能的外在体现。濂川司徒公祠的空间秩序以广府传统宗祠规制为基础，严格按照“三进院落”突出中轴对称、递进式空间、内外分区的特点。</p><h3 id="_2-1-三进两院" tabindex="-1">2.1 三进两院 <a class="header-anchor" href="#_2-1-三进两院" aria-label="Permalink to &quot;2.1 三进两院&quot;">​</a></h3><p>一座祠堂内，沿面阔方向平行的一组单体建筑被称为一进，民间更通俗的说法是以中路的大门数量来计进数，从前到后要进多少次大门，这座祠堂就有几进。进数也可以根据中轴线上的“堂”的数量来计算，濂川谢公祠总体形制范型为标准三进两院，中轴对称。以前后两个天井分隔三进建筑，构成规整封闭的礼制空间。均衡有序的空间格局，是儒家“尊卑有序”伦理的直接体现。</p><p><img src="'+o+'" alt="图1"><img src="'+_+'" alt="图2"></p><p>作为分割三进格局的天井也同时承担了正房和廊的采光和通风，四面坡屋顶雨水汇入天井，经暗沟排出，同时保护墙体与地基。天井院作为岭南传统民居的典型代表，其背后也蕴含中国人讲究四水归堂和方寸之间见天地的思想，而在祠堂中应用，也承载了沟通天上祖先与地上遗民的通道。</p><p><img src="'+n+'" alt="图3"></p><p>而对比来看，坚翁祠堂直接建在四层骑楼之上，底层为民国骑楼商业空间，楼顶保留传统祭祀核心，建筑立面融合了西式山花与传统祠堂的匾额题字，与濂川司徒公祠形成鲜明对比。</p><p><img src="'+l+'" alt="图4"></p><h3 id="_2-2-门——堂——寝" tabindex="-1">2.2 门——堂——寝 <a class="header-anchor" href="#_2-2-门——堂——寝" aria-label="Permalink to &quot;2.2 门——堂——寝&quot;">​</a></h3><p>头门，也称头座、下堂，是祠堂正面最重要的单体建筑、进入祠堂内部的仪式性入口和中轴线序列上的第一座建筑，为设有祠堂的大门，上有祠堂的名号，因此需表现出堂堂正正的气象。濂川司徒公祠为标准双坡硬山屋顶铺设琉璃瓦，檐下梁架木雕与水磨青砖墙共同构成入口处立面。正脊则为陶塑脊，其中灰塑彩绘以本家历史典故为题材，是祠堂门楣教化的传统做法。</p><p><img src="'+c+'" alt="图5"><img src="'+t+'" alt="图6"></p><p>中堂，也称中厅、祭堂、享堂、拜殿，是祠堂的正厅、举行祭祖仪式和宗族议事的主要处所，因此空间最高大宽敞，陈设最为讲究，是祠堂中最具公共性的单体建筑。祭堂中往四根石檐柱和四根木质金柱，俗称八柱厅。</p><p><img src="'+p+'" alt="图7"></p><p>寝堂是安放祖先牌位的建筑，也称上堂、祖堂，在空间序列上是最后一座时亦称后堂、后座。同时其地平较于院落较高，是整个祠堂中尺度最高、位置最尊的单体建筑。更为封闭内敛，形成封闭的私密空间，也体现对于祖先的尊重。</p><p><img src="'+h+'" alt="图8"></p><p>侯成谢公祠则体现外西内中的特点，它的头门处外立面采取西式巴洛克风格拱券柱廊、灰塑山花与浮雕装饰，内部仍保留门匾牌名和灰塑，为侨乡语境下典型的中西融合特征，与濂川司徒公祠完整保留中式装饰形成对比。</p><p><img src="'+d+'" alt="图9"></p><h2 id="三、场所精神-宗族记忆的载体" tabindex="-1">三、场所精神：宗族记忆的载体 <a class="header-anchor" href="#三、场所精神-宗族记忆的载体" aria-label="Permalink to &quot;三、场所精神：宗族记忆的载体&quot;">​</a></h2><p>场所精神产生于当地居民对居住环境的认同感，呈现人对空间事物的感知和对地方记忆的存储，使人对场所产生情感上的依赖，引起人们对价值意义的认同和归属感。</p><p>濂川司徒公祠的场所精神，则天然具有祠堂所代表的宗族归属特性，同时完整保留的传统三进院落空间与中式装饰，也强调了此祠堂本身对于中国传统文化的信仰，敬拜祖先的神圣氛围。</p><h3 id="_3-1-归属感" tabindex="-1">3.1 归属感 <a class="header-anchor" href="#_3-1-归属感" aria-label="Permalink to &quot;3.1 归属感&quot;">​</a></h3><p>濂川司徒公祠是为司徒氏第八世孙濂川公的家族祠堂，维系着分布于开平本地与海外的跨地域宗族认同，是侨乡根脉记忆的物理锚点。除却上文提到的空间秩序，门额题字、教化彩绘祠堂内的的宗族谱系，都共同构建了慎终追远的综合性场所氛围，将宗族的历史记忆注入空间，使建筑本身成为追思先祖的一部分。</p><p>仓东计划通过改造、宣传、举办活动等方式，也重建了子嗣与场所，也就是侯成谢公祠的情感联结。</p><p><img src="'+t+'" alt="图6"><img src="'+m+'" alt="图10"></p><h3 id="_3-2-神圣性" tabindex="-1">3.2 神圣性 <a class="header-anchor" href="#_3-2-神圣性" aria-label="Permalink to &quot;3.2 神圣性&quot;">​</a></h3><p>于街巷到祠堂入口前处，再经头门、天井、中堂，最终抵达寝堂，濂川司徒公祠的空间序列呈现由俗入圣、由公入私的递进节奏，界定了礼仪边界，经过中堂公共性至内向性的过渡，尽端的寝堂则通过封闭围合和放牌位，成为宗族后代敬祖追远的神圣空间。</p><p>侯成谢公祠的西式立面弱化了入口的仪式边界，坚翁祠堂则因一楼为商的改造打破了序列的递进关系，但濂川司徒公祠也因商业化布置，较于侯成谢公祠的正面放置牌位，它增加了放置文创商品的空间，这些都在不同程度上削弱了一部分祠堂原有的场所精神。</p><p><img src="'+g+'" alt="图11"></p><h2 id="四、批判性反思-对比视角下的价值反思与保护路径" tabindex="-1">四、批判性反思：对比视角下的价值反思与保护路径 <a class="header-anchor" href="#四、批判性反思-对比视角下的价值反思与保护路径" aria-label="Permalink to &quot;四、批判性反思：对比视角下的价值反思与保护路径&quot;">​</a></h2><h3 id="_4-1-形制优先的保护模式" tabindex="-1">4.1 形制优先的保护模式 <a class="header-anchor" href="#_4-1-形制优先的保护模式" aria-label="Permalink to &quot;4.1 形制优先的保护模式&quot;">​</a></h3><p>借濂川司徒公祠的视角，笔者发现侨乡祠堂或许存在重视物质修复而轻文化延续的倾向，将祠堂简化为静态的建筑标本，陷入了保护形制即保护文化传承的误区。其硬山顶、水磨青砖、三进院落等传统形制虽得到完整保留，但作为场所精神核心的祭祀仪式和宗族议事等三堂理应保有的功能却近乎消失，而都转为宣传与售卖与当地传统文化联系不大的普通文创与文艺装饰。</p><p>这种保护模式本质上是将宗祠的文化价值窄化为建筑形制，忽视了场所精神的核心——人与空间的持续互动。例如可以将商业空间与祭祀空间区分开来，重新装饰牌位与年代老照片，恢复一部分其原有功能，定期举办祭祖议事活动，深掘本土文化与宗族传承的同时保有侧廊售卖商品区域，既不影响人们走进场所的第一印象，也能在回程动线被商品所吸引。</p><p>仅修复形制而轻视场所精神，或会让宗祠沦为网红景观的空壳，而无法真正实现文化遗产的活态转化。</p><p><img src="'+u+'" alt="图12"></p><h3 id="_4-2-侨乡宗祠的身份缺失" tabindex="-1">4.2 侨乡宗祠的身份缺失 <a class="header-anchor" href="#_4-2-侨乡宗祠的身份缺失" aria-label="Permalink to &quot;4.2 侨乡宗祠的身份缺失&quot;">​</a></h3><p>濂川司徒公祠作为侨乡祠堂，其文化价值不仅在于岭南传统礼制，更在于它作为跨地域，跨国家宗族认同锚点的特殊意义。然而，当前的活化叙事过度偏向传统的“有钱广东人以前住的宅子”的普适性宣传，而弱化了其作为司徒氏支脉祠堂、维系海内外侨裔根脉认同的独特性。</p><p>一方面其保证了传统空间秩序与装饰，但另一方面这种叙事策略虽然降低了文化解读的门槛，却消解了宗祠的侨乡性，使其与其他地区的普通祠堂同质化。对于建筑和空间来说，除了融合西式装饰元素，或还能通过布置侨乡生活场景作为动线节点，同样放置于前中侧廊，保证寝堂神圣性的同时增添侨乡回忆。</p><p><img src="'+p+'" alt="图7"></p><h2 id="五、结论" tabindex="-1">五、结论 <a class="header-anchor" href="#五、结论" aria-label="Permalink to &quot;五、结论&quot;">​</a></h2><p>本文以濂川司徒公祠为研究主体，对比侯成谢公祠与坚翁祠堂，探讨广府侨乡宗祠的空间秩序、场所精神及当代活化路径。</p><p>在空间秩序上，濂川司徒公祠保留完整的三进两院与门——堂——寝规制，以严谨的递进式空间和岭南传统装饰，直观体现儒家礼制伦理与广东传统营造的特色。</p><p>在场所精神上，祠堂作为司徒氏跨地域的宗族记忆载体，承载着强烈的归属感与敬祖神圣性，是侨乡根脉认同的重要空间锚点。但在文旅开发中，其祭祖功能弱化和商业空间侵入，导致场所精神被一定程度消解。</p><p>反思当前保护现状可见，侨乡宗祠存在重形制修复、轻活态传承与同质化严重的问题。从环境设计视角出发，应通过空间分层设计厘清祭祀与商业边界，恢复宗祠文化活力，同时以场景叙事强化侨乡特质，避免仅以西式元素定义侨乡特征。</p><p>综上，濂川司徒公祠是广府传统宗祠的珍贵样本。唯有平衡形制保护和场所精神传承，才能让宗祠真正成为延续宗族文化、承载侨乡记忆的活态载体。</p>',51)])])}const D=r(k,[["render",q]]);export{S as __pageData,D as default};
